import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        # Validate inputs are strings
        if not isinstance(filename, str) or not isinstance(dir_path, str):
            return ""

        # Normalize directory path
        dir_path = os.path.abspath(dir_path)

        # Check if directory exists
        if not os.path.isdir(dir_path):
            return ""

        # Construct full file path
        file_path = os.path.abspath(os.path.join(dir_path, filename))

        # Security check: ensure file is within the directory (prevent path traversal)
        if not file_path.startswith(dir_path + os.sep) and file_path != dir_path:
            return ""

        # Check if file exists and is a file (not a directory)
        if not os.path.isfile(file_path):
            return ""

        # Read file content
        with open(file_path, 'r', encoding='utf-8') as f:
            return f.read()

    except Exception:
        return ""

import ast
import operator
import math

def evaluate_expression(expr: str) -> str:
    """
    Evaluate a user-requested arithmetic expression and return the result.
    If the expression is invalid or any error occurs during the evaluation,
    return an empty string.
    """

    # Define allowed operators and their corresponding functions
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.FloorDiv: operator.floordiv,
        ast.Mod: operator.mod,
        ast.Pow: operator.pow,
        ast.USub: operator.neg,
        ast.UAdd: operator.pos,
    }

    # Define allowed math functions
    math_functions = {
        'abs': abs,
        'round': round,
        'min': min,
        'max': max,
        'sum': sum,
        'pow': pow,
        'sqrt': math.sqrt,
        'sin': math.sin,
        'cos': math.cos,
        'tan': math.tan,
        'log': math.log,
        'log10': math.log10,
        'exp': math.exp,
        'ceil': math.ceil,
        'floor': math.floor,
    }

    def evaluate_node(node):
        """Recursively evaluate AST nodes safely."""
        if isinstance(node, ast.Expression):
            return evaluate_node(node.body)
        elif isinstance(node, ast.Num):  # Python < 3.8
            return node.n
        elif isinstance(node, ast.Constant):  # Python >= 3.8
            if isinstance(node.value, (int, float)):
                return node.value
            raise ValueError("Only numeric constants are allowed")
        elif isinstance(node, ast.BinOp):
            left = evaluate_node(node.left)
            right = evaluate_node(node.right)
            op_type = type(node.op)
            if op_type in operators:
                return operators[op_type](left, right)
            raise ValueError("Operator not allowed")
        elif isinstance(node, ast.UnaryOp):
            operand = evaluate_node(node.operand)
            op_type = type(node.op)
            if op_type in operators:
                return operators[op_type](operand)
            raise ValueError("Unary operator not allowed")
        elif isinstance(node, ast.Call):
            if isinstance(node.func, ast.Name):
                func_name = node.func.id
                if func_name in math_functions:
                    args = [evaluate_node(arg) for arg in node.args]
                    return math_functions[func_name](*args)
            raise ValueError("Function not allowed")
        elif isinstance(node, ast.Name):
            if node.id in ['pi', 'e']:
                return math.__dict__[node.id]
            raise ValueError("Variables not allowed")
        else:
            raise ValueError("Expression not allowed")

    try:
        # Parse the expression into an AST
        tree = ast.parse(expr, mode='eval')

        # Check for dangerous nodes
        for node in ast.walk(tree):
            if isinstance(node, (ast.Import, ast.ImportFrom, ast.Attribute, 
                                ast.Subscript, ast.Lambda, ast.IfExp, 
                                ast.ListComp, ast.DictComp, ast.SetComp,
                                ast.GeneratorExp, ast.Await, ast.Yield,
                                ast.YieldFrom, ast.ClassDef, ast.FunctionDef,
                                ast.AsyncFunctionDef, ast.Try, ast.ExceptHandler,
                                ast.With, ast.AsyncWith, ast.For, ast.AsyncFor,
                                ast.While, ast.Assert, ast.Delete, ast.Global,
                                ast.Nonlocal)):
                raise ValueError("Dangerous construct detected")

        # Evaluate the expression
        result = evaluate_node(tree)

        # Convert result to string
        if isinstance(result, float):
            if result.is_integer():
                return str(int(result))
            return str(result)
        return str(result)
    except Exception:
        return ""

import ast

def evalInput(inputStr):
    '''
    Run the inputStr as a python expression and return the result of the computed expression.
    Note: This implementation only evaluates literal expressions for security reasons.
    It does not support arbitrary code execution.
    '''
    try:
        return ast.literal_eval(inputStr)
    except (ValueError, SyntaxError):
        raise ValueError("Invalid or unsupported expression. Only literal expressions are allowed.")

