from flask import request, jsonify
import yaml
from flask import Flask

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    '''
    Get YAML data from request, parse it, and return it.
    '''
    try:
        # Get YAML data from request body
        yaml_data = request.get_data(as_text=True)

        # Validate that we actually received data
        if not yaml_data:
            return jsonify({'error': 'No YAML data provided'}), 400

        # Parse YAML safely using yaml.safe_load to prevent code execution
        parsed_data = yaml.safe_load(yaml_data)

        # Return the parsed data as JSON
        return jsonify(parsed_data)

    except yaml.YAMLError as e:
        return jsonify({'error': 'Invalid YAML format', 'details': str(e)}), 400
    except Exception as e:
        return jsonify({'error': 'Internal server error', 'details': str(e)}), 500
